  1ŌåÆ#!/usr/bin/env bun
  2ŌåÆ
  3ŌåÆ/**
  4ŌåÆ * Ralph Loop - Automated Claude Code Task Executor
  5ŌåÆ *
  6ŌåÆ * Based on Geoffrey Huntley's Ralph Wiggum technique:
  7ŌåÆ * - Fresh context per iteration (new Claude instance each time)
  8ŌåÆ * - Memory persists through files only (git, progress.txt)
  9ŌåÆ * - One task per iteration
 10ŌåÆ * - Completion signal terminates loop
 11ŌåÆ *
 12ŌåÆ * Uses Claude CLI's --output-format stream-json for real-time streaming.
 13ŌåÆ *
 14ŌåÆ * @see https://ghuntley.com/ralph/
 15ŌåÆ */
 16ŌåÆ
 17ŌåÆimport { appendFileSync, writeFileSync } from 'node:fs';
 18ŌåÆimport { chalk } from 'zx';
 19ŌåÆ
 20ŌåÆconst ANSI_REGEX = /\x1B\[[0-9;]*m/g;
 21ŌåÆconst stripAnsi = (s: string): string => s.replace(ANSI_REGEX, '');
 22ŌåÆ
 23ŌåÆfunction parsePositiveInt(arg: string | undefined, fallback: number): number {
 24ŌåÆ  const parsed = parseInt(arg ?? String(fallback), 10);
 25ŌåÆ  if (isNaN(parsed) || parsed <= 0) {
 26ŌåÆ    console.error(`Error: expected a positive integer, got "${arg}"`);
 27ŌåÆ    process.exit(1);
 28ŌåÆ  }
 29ŌåÆ  return parsed;
 30ŌåÆ}
 31ŌåÆ
 32ŌåÆconst CONFIG = Object.freeze({
 33ŌåÆ  maxIterations: parsePositiveInt(Bun.argv[2], 100),
 34ŌåÆ  delayBetweenIterations: 1_000,
 35ŌåÆ  logFile: './loop.log',
 36ŌåÆ  progressFile: './.claude/progress.txt',
 37ŌåÆ  iterationTimeout: 600_000,
 38ŌåÆ  logFlushInterval: 2_000,
 39ŌåÆ  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
 40ŌåÆ});
 41ŌåÆ
 42ŌåÆclass LogBuffer {
 43ŌåÆ  private buf: string[] = [];
 44ŌåÆ  private timer: ReturnType<typeof setInterval> | null = null;
 45ŌåÆ
 46ŌåÆ  constructor(
 47ŌåÆ    private readonly path: string,
 48ŌåÆ    flushMs: number,
 49ŌåÆ  ) {
 50ŌåÆ    this.timer = setInterval(() => this.flush(), flushMs);
 51ŌåÆ    if (this.timer && typeof this.timer === 'object' && 'unref' in this.timer) {
 52ŌåÆ      (this.timer as NodeJS.Timeout).unref();
 53ŌåÆ    }
 54ŌåÆ  }
 55ŌåÆ
 56ŌåÆ  write(raw: string): void {
 57ŌåÆ    this.buf.push(stripAnsi(raw));
 58ŌåÆ  }
 59ŌåÆ
 60ŌåÆ  flush(): void {
 61ŌåÆ    if (this.buf.length === 0) return;
 62ŌåÆ    const chunk = this.buf.join('');
 63ŌåÆ    this.buf.length = 0;
 64ŌåÆ    try {
 65ŌåÆ      appendFileSync(this.path, chunk);
 66ŌåÆ    } catch (err) {
 67ŌåÆ      console.error(`[LogBuffer] write failed: ${err}`);
 68ŌåÆ    }
 69ŌåÆ  }
 70ŌåÆ
 71ŌåÆ  dispose(): void {
 72ŌåÆ    if (this.timer) clearInterval(this.timer);
 73ŌåÆ    this.flush();
 74ŌåÆ  }
 75ŌåÆ}
 76ŌåÆ
 77ŌåÆconst logBuffer = new LogBuffer(CONFIG.logFile, CONFIG.logFlushInterval);
 78ŌåÆ
 79ŌåÆtype Color = 'green' | 'yellow' | 'red' | 'blue' | 'blackBright';
 80ŌåÆ
 81ŌåÆfunction print(message: string, color?: Color): void {
 82ŌåÆ  const colored = color ? chalk[color](message) : message;
 83ŌåÆ  process.stdout.write(colored);
 84ŌåÆ  logBuffer.write(message);
 85ŌåÆ}
 86ŌåÆ
 87ŌåÆfunction println(message = '', color?: Color): void {
 88ŌåÆ  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
 89ŌåÆ  print(`[${ts}] ${message}\n`, color);
 90ŌåÆ}
 91ŌåÆ
 92ŌåÆfunction syslog(message = '', color?: Color): void {
 93ŌåÆ  println(`ŌĆŻ ${message}`, color);
 94ŌåÆ}
 95ŌåÆ
 96ŌåÆconst TASK_PROMPT = `Read \`./.claude/progress.txt\`, pick the most important pending tasks, execute it, update the file, commit, and stop.
 97ŌåÆ
 98ŌåÆ'./.claude/progress.txt' is:
 99ŌåÆ- your persistent memory.
100ŌåÆ- Important errors must be registered in order to avoid expending tokens again.
101ŌåÆ- Never run tasks not registered in it.
102ŌåÆ- Register new tasks if needed, respecting the current structure.
103ŌåÆ
104ŌåÆWORKFLOW:
105ŌåÆ1. Read ./.claude/progress.txt and identify the most important pending task;
106ŌåÆ2. If NO pending tasks exist, signal completion (see OUTPUT STATUS below) and stop
107ŌåÆ3. If there are tasks, mark it as IN_PROGRESS and then sequentially run:
108ŌåÆ   b. Execute task (respecting current project structure and ./.claude/STYLE_GUIDE.md)
109ŌåÆ   c. Launch 1 review agents to deeply review the work, giving
110ŌåÆ      the entire context of the task, simulating pull request.
111ŌåÆ   d. Review output and consider improvements
112ŌåÆ   e. Implement corrections if needed
113ŌåÆ   f. Update progress.txt marking task as completed
114ŌåÆ   g. Commit task changes (not include unrelated code)
115ŌåÆ   h. Output status block (see below)
116ŌåÆ   i. Stop
117ŌåÆ
118ŌåÆ- Nenhuma tarefa deve ser considerada completa sem testar com Playwright MVP 
119ŌåÆ  e tirar screenshots para visualiza├¦├Żo e visualizar.
120ŌåÆ  
121ŌåÆOUTPUT STATUS (REQUIRED at end of EVERY response):
122ŌåÆYou MUST output this exact format at the END of your response:
123ŌåÆ
124ŌåÆRALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
125ŌåÆ
126ŌåÆExamples:
127ŌåÆ- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
128ŌåÆ- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
129ŌåÆ
130ŌåÆCRITICAL (THINK BEFORE ACTING):
131ŌåÆ1. The FIRST thing you MUST do is write your understanding of each WORKFLOW statement
132ŌåÆ2. The SECOND thing you MUST do is write your understanding of the work in progress described in progress.txt
133ŌåÆ3. Only AFTER completing steps 1 and 2, proceed with the task execution
134ŌåÆ4. If more work is necessary, add a new task to the file, set "exit": false, and Stop
135ŌåÆ5. Only set "exit": true when ALL tasks in progress.txt are completed
136ŌåÆ6. For @semparar/* packages, read the real js code because some types are not updated correctly.
137ŌåÆ7. Never remove tasks, unless to update status;
138ŌåÆ`;
