140ŌåÆinterface ContentBlock {
141ŌåÆ  type: 'text' | 'tool_use' | 'tool_result';
142ŌåÆ  text?: string;
143ŌåÆ  name?: string;
144ŌåÆ  input?: unknown;
145ŌåÆ  content?:
146ŌåÆ    | string
147ŌåÆ    | Array<{
148ŌåÆ        type: string;
149ŌåÆ        text?: string;
150ŌåÆ      }>;
151ŌåÆ}
152ŌåÆ
153ŌåÆinterface StreamMessage {
154ŌåÆ  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
155ŌåÆ  subtype?: string;
156ŌåÆ  role?: 'assistant' | 'user';
157ŌåÆ  event?: {
158ŌåÆ    type: string;
159ŌåÆ    delta?: {
160ŌåÆ      type: string;
161ŌåÆ      text?: string;
162ŌåÆ    };
163ŌåÆ  };
164ŌåÆ  result?: string;
165ŌåÆ  message?: {
166ŌåÆ    role?: string;
167ŌåÆ    content?: ContentBlock[];
168ŌåÆ  };
169ŌåÆ  content?: ContentBlock[];
170ŌåÆ}
171ŌåÆ
172ŌåÆinterface RalphStatus {
173ŌåÆ  exit: boolean;
174ŌåÆ  task: string;
175ŌåÆ  remaining: number;
176ŌåÆ}
177ŌåÆ
178ŌåÆfunction parseRalphStatus(output: string): RalphStatus | null {
179ŌåÆ  const marker = output.lastIndexOf('RALPH_STATUS:');
180ŌåÆ  if (marker === -1) return null;
181ŌåÆ
182ŌåÆ  const jsonStart = output.indexOf('{', marker);
183ŌåÆ  if (jsonStart === -1) return null;
184ŌåÆ
185ŌåÆ  let depth = 0;
186ŌåÆ  for (let i = jsonStart; i < output.length; i++) {
187ŌåÆ    if (output[i] === '{') depth++;
188ŌåÆ    if (output[i] === '}') depth--;
189ŌåÆ    if (depth === 0) {
190ŌåÆ      try {
191ŌåÆ        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
192ŌåÆ        if (typeof parsed.exit === 'boolean') {
193ŌåÆ          return parsed as RalphStatus;
194ŌåÆ        }
195ŌåÆ      } catch {}
196ŌåÆ      return null;
197ŌåÆ    }
198ŌåÆ  }
199ŌåÆ  return null;
200ŌåÆ}
201ŌåÆ
202ŌåÆlet currentProc: ReturnType<typeof Bun.spawn> | null = null;
203ŌåÆ
204ŌåÆfunction killCurrentProc(): void {
205ŌåÆ  if (!currentProc) return;
206ŌåÆ  try {
207ŌåÆ    currentProc.kill();
208ŌåÆ  } catch {}
209ŌåÆ}
210ŌåÆ
211ŌåÆasync function checkDependencies(): Promise<void> {
212ŌåÆ  const result = await Bun.$`which claude`.quiet().nothrow();
213ŌåÆ  if (result.exitCode !== 0) {
214ŌåÆ    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
215ŌåÆ    process.exit(1);
216ŌåÆ  }
217ŌåÆ
218ŌåÆ  if (!(await Bun.file(CONFIG.progressFile).exists())) {
219ŌåÆ    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
220ŌåÆ    process.exit(1);
221ŌåÆ  }
222ŌåÆ}
223ŌåÆ
224ŌåÆinterface IterationResult {
225ŌåÆ  output: string;
226ŌåÆ  exitCode: number;
227ŌåÆ  timedOut: boolean;
228ŌåÆ}
229ŌåÆ
230ŌåÆasync function runIteration(): Promise<IterationResult> {
231ŌåÆ  syslog('Executing Claude Code...');
232ŌåÆ
233ŌåÆ  const proc = Bun.spawn(
234ŌåÆ    [
235ŌåÆ      'claude',
236ŌåÆ      '-p',
237ŌåÆ      TASK_PROMPT,
238ŌåÆ      '--verbose',
239ŌåÆ      '--debug',
240ŌåÆ      '--dangerously-skip-permissions',
241ŌåÆ      '--output-format',
242ŌåÆ      'stream-json',
243ŌåÆ      '--include-partial-messages',
244ŌåÆ      '--model=opus',
245ŌåÆ    ],
246ŌåÆ    {
247ŌåÆ      cwd: process.cwd(),
248ŌåÆ      env: process.env,
249ŌåÆ      stdout: 'pipe',
250ŌåÆ      stderr: 'inherit',
251ŌåÆ    },
252ŌåÆ  );
253ŌåÆ
254ŌåÆ  currentProc = proc;
255ŌåÆ
256ŌåÆ  const chunks: string[] = [];
257ŌåÆ  let timedOut = false;
258ŌåÆ  const decoder = new TextDecoder();
259ŌåÆ  let buffer = '';
260ŌåÆ  let blockHasContent = false;
261ŌåÆ
262ŌåÆ  const timeoutId = setTimeout(() => {
263ŌåÆ    timedOut = true;
264ŌåÆ    syslog('Iteration timeout reached. Killing process...', 'yellow');
265ŌåÆ    killCurrentProc();
266ŌåÆ  }, CONFIG.iterationTimeout);
267ŌåÆ
268ŌåÆ  const reader = proc.stdout.getReader();
269ŌåÆ
270ŌåÆ  try {
271ŌåÆ    while (true) {
272ŌåÆ      const { done, value } = await reader.read();
273ŌåÆ      if (done) break;
274ŌåÆ
275ŌåÆ      buffer += decoder.decode(value, { stream: true });
276ŌåÆ
277ŌåÆ      const lines = buffer.split('\n');
278ŌåÆ      buffer = lines.pop() || '';
279ŌåÆ
280ŌåÆ      for (const line of lines) {
281ŌåÆ        if (!line.trim()) continue;
282ŌåÆ
283ŌåÆ        let msg: StreamMessage;
284ŌåÆ        try {
285ŌåÆ          msg = JSON.parse(line);
286ŌåÆ        } catch {
287ŌåÆ          continue;
288ŌåÆ        }
289ŌåÆ
290ŌåÆ        if (msg.type === 'stream_event') {
291ŌåÆ          const evt = msg.event;
292ŌåÆ          if (!evt) continue;
293ŌåÆ
294ŌåÆ          if (evt.type === 'content_block_start') {
295ŌåÆ            blockHasContent = false;
296ŌåÆ          } else if (evt.type === 'content_block_delta') {
297ŌåÆ            const text = evt.delta?.text;
298ŌåÆ            if (text) {
299ŌåÆ              print(text);
300ŌåÆ              chunks.push(text);
301ŌåÆ              blockHasContent = true;
302ŌåÆ            }
303ŌåÆ          } else if (evt.type === 'content_block_stop' && blockHasContent) {
304ŌåÆ            print('\n');
305ŌåÆ            chunks.push('\n');
306ŌåÆ            blockHasContent = false;
307ŌåÆ          }
308ŌåÆ          continue;
309ŌåÆ        }
310ŌåÆ
311ŌåÆ        if (msg.type === 'assistant' || msg.type === 'message') {
312ŌåÆ          // Content already streamed via content_block_delta events.
313ŌåÆ          // Only print here as fallback if no streaming occurred.
314ŌåÆ          const blocks = msg.message?.content ?? msg.content;
315ŌåÆ          if (!Array.isArray(blocks)) continue;
316ŌåÆ
317ŌåÆ          for (const block of blocks) {
318ŌåÆ            if (block.type === 'text' && block.text && chunks.length === 0) {
319ŌåÆ              print(block.text);
320ŌåÆ              chunks.push(block.text);
321ŌåÆ              print('\n');
322ŌåÆ              chunks.push('\n');
323ŌåÆ            }
324ŌåÆ          }
325ŌåÆ          continue;
326ŌåÆ        }
327ŌåÆ
328ŌåÆ        if (msg.type === 'user') {
329ŌåÆ          const blocks = msg.message?.content ?? msg.content;
330ŌåÆ          if (!Array.isArray(blocks)) continue;
331ŌåÆ
332ŌåÆ          for (const block of blocks) {
333ŌåÆ            //
334ŌåÆ            // Handling tool result
335ŌåÆ            if (block.type === 'tool_result' && block.content) {
336ŌåÆ              const rawContent =
337ŌåÆ                typeof block.content === 'string'
338ŌåÆ                  ? block.content
339ŌåÆ                  : block.content
340ŌåÆ                      .map(c => c.text ?? '')
341ŌåÆ                      .filter(Boolean)
342ŌåÆ                      .join('\n');
343ŌåÆ
344ŌåÆ              if (!rawContent) continue;
345ŌåÆ
346ŌåÆ              let trimmed = rawContent.trim().slice(0, 320);
347ŌåÆ
348ŌåÆ              const toolResult =
349ŌåÆ                trimmed && trimmed !== rawContent
350ŌåÆ                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
351ŌåÆ                  : rawContent;
352ŌåÆ
353ŌåÆ              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
354ŌåÆ              chunks.push('\n', rawContent, '\n');
355ŌåÆ            }
356ŌåÆ          }
357ŌåÆ          continue;
358ŌåÆ        }
359ŌåÆ
360ŌåÆ        if (msg.type === 'result' && msg.result) {
361ŌåÆ          if (chunks.length === 0) {
362ŌåÆ            chunks.push(msg.result);
363ŌåÆ          }
364ŌåÆ        }
365ŌåÆ      }
366ŌåÆ    }
367ŌåÆ
368ŌåÆ    if (buffer.trim()) {
369ŌåÆ      try {
370ŌåÆ        const msg: StreamMessage = JSON.parse(buffer);
371ŌåÆ        if (msg.type === 'result' && msg.result && chunks.length === 0) {
372ŌåÆ          chunks.push(msg.result);
373ŌåÆ        }
374ŌåÆ      } catch {}
375ŌåÆ    }
376ŌåÆ  } finally {
377ŌåÆ    clearTimeout(timeoutId);
378ŌåÆ    reader.releaseLock();
379ŌåÆ    currentProc = null;
380ŌåÆ    logBuffer.flush();
381ŌåÆ  }
382ŌåÆ
383ŌåÆ  const output = chunks.join('');
384ŌåÆ
385ŌåÆ  if (timedOut) {
386ŌåÆ    return {
387ŌåÆ      output,
388ŌåÆ      exitCode: 124,
389ŌåÆ      timedOut: true,
390ŌåÆ    };
391ŌåÆ  }
392ŌåÆ
393ŌåÆ  const exitCode = await proc.exited;
394ŌåÆ  println();
395ŌåÆ  return {
396ŌåÆ    output,
397ŌåÆ    exitCode,
398ŌåÆ    timedOut: false,
399ŌåÆ  };
400ŌåÆ}
401ŌåÆ
402ŌåÆfunction printHeader(): void {
403ŌåÆ  println();
404ŌåÆ  println('==========================================', 'blue');
405ŌåÆ  println('   Ralph Loop - Bun.js Edition', 'blue');
406ŌåÆ  println('==========================================', 'blue');
407ŌåÆ  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
408ŌåÆ  println(`Log file:       ${chalk.yellow(CONFIG.logFile)}`);
409ŌåÆ  println(
410ŌåÆ    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
411ŌåÆ  );
412ŌåÆ  println(
413ŌåÆ    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
414ŌåÆ  );
415ŌåÆ  println();
416ŌåÆ}
417ŌåÆ
418ŌåÆasync function main(): Promise<void> {
419ŌåÆ  let cleanupCalled = false;
420ŌåÆ
421ŌåÆ  const cleanup = (signal: string) => {
422ŌåÆ    if (cleanupCalled) return;
423ŌåÆ    cleanupCalled = true;
424ŌåÆ    println();
425ŌåÆ    syslog(`Interrupted by ${signal}. Cleaning up...`);
426ŌåÆ    killCurrentProc();
427ŌåÆ    logBuffer.dispose();
428ŌåÆ    process.exit(signal === 'SIGINT' ? 130 : 143);
429ŌåÆ  };
430ŌåÆ
431ŌåÆ  process.on('SIGINT', () => cleanup('SIGINT'));
432ŌåÆ  process.on('SIGTERM', () => cleanup('SIGTERM'));
433ŌåÆ
434ŌåÆ  await checkDependencies();
435ŌåÆ
436ŌåÆ  writeFileSync(CONFIG.logFile, '');
437ŌåÆ
438ŌåÆ  printHeader();
439ŌåÆ  syslog('Starting automated task loop...');
440ŌåÆ
441ŌåÆ  let consecutiveFailures = 0;
442ŌåÆ  const MAX_CONSECUTIVE_FAILURES = 3;
443ŌåÆ
444ŌåÆ  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
445ŌåÆ    println();
446ŌåÆ    println('==========================================', 'green');
447ŌåÆ    syslog(`Iteration #${iteration} / ${CONFIG.maxIterations}`, 'green');
448ŌåÆ    println('==========================================', 'green');
449ŌåÆ    println();
450ŌåÆ
451ŌåÆ    const { output, exitCode, timedOut } = await runIteration();
452ŌåÆ
453ŌåÆ    if (exitCode === 0) {
454ŌåÆ      syslog('Claude Code completed successfully', 'green');
455ŌåÆ      consecutiveFailures = 0;
456ŌåÆ    } else {
457ŌåÆ      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
458ŌåÆ      consecutiveFailures++;
459ŌåÆ    }
460ŌåÆ
461ŌåÆ    if (consecutiveFailures >= MAX_CONSECUTIVE_FAILURES) {
462ŌåÆ      println();
463ŌåÆ      println('==========================================', 'red');
464ŌåÆ      syslog(
465ŌåÆ        `${MAX_CONSECUTIVE_FAILURES} consecutive failures ŌĆö aborting loop`,
466ŌåÆ        'red',
467ŌåÆ      );
468ŌåÆ      println('==========================================', 'red');
469ŌåÆ      logBuffer.dispose();
470ŌåÆ      process.exit(1);
471ŌåÆ    }
472ŌåÆ
473ŌåÆ    const status = parseRalphStatus(output);
474ŌåÆ
475ŌåÆ    if (status?.exit) {
476ŌåÆ      println();
477ŌåÆ      println('==========================================', 'green');
478ŌåÆ      syslog('ALL TASKS COMPLETED!', 'green');
479ŌåÆ      syslog(`Final task:      ${status.task}`, 'green');
480ŌåÆ      syslog(`Remaining:       ${status.remaining}`, 'green');
481ŌåÆ      syslog(`Total iterations: ${iteration}`, 'green');
482ŌåÆ      println('==========================================', 'green');
483ŌåÆ      logBuffer.dispose();
484ŌåÆ      process.exit(0);
485ŌåÆ    }
486ŌåÆ
487ŌåÆ    if (status) {
488ŌåÆ      syslog(
489ŌåÆ        `Task done: "${status.task}" ŌĆö ${status.remaining} remaining`,
490ŌåÆ        'blue',
491ŌåÆ      );
492ŌåÆ    } else if (!timedOut && exitCode === 0) {
493ŌåÆ      syslog(
494ŌåÆ        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
495ŌåÆ        'yellow',
496ŌåÆ      );
497ŌåÆ    }
498ŌåÆ
499ŌåÆ    if (iteration < CONFIG.maxIterations) {
500ŌåÆ      const delaySec = CONFIG.delayBetweenIterations / 1_000;
501ŌåÆ      println();
502ŌåÆ      syslog(`Waiting ${delaySec}s before next iteration...`);
503ŌåÆ      await Bun.sleep(CONFIG.delayBetweenIterations);
504ŌåÆ    }
505ŌåÆ  }
506ŌåÆ
507ŌåÆ  println();
508ŌåÆ  println('==========================================', 'red');
509ŌåÆ  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
510ŌåÆ  syslog('Loop stopped ŌĆö tasks may still be pending', 'red');
511ŌåÆ  println('==========================================', 'red');
512ŌåÆ  logBuffer.dispose();
513ŌåÆ  process.exit(1);
514ŌåÆ}
515ŌåÆ
516ŌåÆmain();
