178ŌåÆfunction parseRalphStatus(output: string): RalphStatus | null {
179ŌåÆ  const marker = output.lastIndexOf('RALPH_STATUS:');
180ŌåÆ  if (marker === -1) return null;
181ŌåÆ
182ŌåÆ  const jsonStart = output.indexOf('{', marker);
183ŌåÆ  if (jsonStart === -1) return null;
184ŌåÆ
185ŌåÆ  let depth = 0;
186ŌåÆ  for (let i = jsonStart; i < output.length; i++) {
187ŌåÆ    if (output[i] === '{') depth++;
188ŌåÆ    if (output[i] === '}') depth--;
189ŌåÆ    if (depth === 0) {
190ŌåÆ      try {
191ŌåÆ        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
192ŌåÆ        if (typeof parsed.exit === 'boolean') {
193ŌåÆ          return parsed as RalphStatus;
194ŌåÆ        }
195ŌåÆ      } catch {}
196ŌåÆ      return null;
197ŌåÆ    }
198ŌåÆ  }
199ŌåÆ  return null;
200ŌåÆ}
