230ŌåÆasync function runIteration(): Promise<IterationResult> {
231ŌåÆ  syslog('Executing Claude Code...');
232ŌåÆ
233ŌåÆ  const proc = Bun.spawn(
234ŌåÆ    [
235ŌåÆ      'claude',
236ŌåÆ      '-p',
237ŌåÆ      TASK_PROMPT,
238ŌåÆ      '--verbose',
239ŌåÆ      '--debug',
240ŌåÆ      '--dangerously-skip-permissions',
241ŌåÆ      '--output-format',
242ŌåÆ      'stream-json',
243ŌåÆ      '--include-partial-messages',
244ŌåÆ      '--model=opus',
245ŌåÆ    ],
246ŌåÆ    {
247ŌåÆ      cwd: process.cwd(),
248ŌåÆ      env: process.env,
249ŌåÆ      stdout: 'pipe',
250ŌåÆ      stderr: 'inherit',
251ŌåÆ    },
252ŌåÆ  );
253ŌåÆ
254ŌåÆ  currentProc = proc;
255ŌåÆ
256ŌåÆ  const chunks: string[] = [];
257ŌåÆ  let timedOut = false;
258ŌåÆ  const decoder = new TextDecoder();
259ŌåÆ  let buffer = '';
260ŌåÆ  let blockHasContent = false;
261ŌåÆ
262ŌåÆ  const timeoutId = setTimeout(() => {
263ŌåÆ    timedOut = true;
264ŌåÆ    syslog('Iteration timeout reached. Killing process...', 'yellow');
265ŌåÆ    killCurrentProc();
266ŌåÆ  }, CONFIG.iterationTimeout);
267ŌåÆ
268ŌåÆ  const reader = proc.stdout.getReader();
269ŌåÆ
270ŌåÆ  try {
271ŌåÆ    while (true) {
272ŌåÆ      const { done, value } = await reader.read();
273ŌåÆ      if (done) break;
274ŌåÆ
275ŌåÆ      buffer += decoder.decode(value, { stream: true });
276ŌåÆ
277ŌåÆ      const lines = buffer.split('\n');
278ŌåÆ      buffer = lines.pop() || '';
279ŌåÆ
280ŌåÆ      for (const line of lines) {
281ŌåÆ        if (!line.trim()) continue;
282ŌåÆ
283ŌåÆ        let msg: StreamMessage;
284ŌåÆ        try {
285ŌåÆ          msg = JSON.parse(line);
286ŌåÆ        } catch {
287ŌåÆ          continue;
288ŌåÆ        }
289ŌåÆ
290ŌåÆ        if (msg.type === 'stream_event') {
291ŌåÆ          const evt = msg.event;
292ŌåÆ          if (!evt) continue;
293ŌåÆ
294ŌåÆ          if (evt.type === 'content_block_start') {
295ŌåÆ            blockHasContent = false;
296ŌåÆ          } else if (evt.type === 'content_block_delta') {
297ŌåÆ            const text = evt.delta?.text;
298ŌåÆ            if (text) {
299ŌåÆ              print(text);
300ŌåÆ              chunks.push(text);
301ŌåÆ              blockHasContent = true;
302ŌåÆ            }
303ŌåÆ          } else if (evt.type === 'content_block_stop' && blockHasContent) {
304ŌåÆ            print('\n');
305ŌåÆ            chunks.push('\n');
306ŌåÆ            blockHasContent = false;
307ŌåÆ          }
308ŌåÆ          continue;
309ŌåÆ        }
310ŌåÆ
311ŌåÆ        if (msg.type === 'assistant' || msg.type === 'message') {
312ŌåÆ          // Content already streamed via content_block_delta events.
313ŌåÆ          // Only print here as fallback if no streaming occurred.
314ŌåÆ          const blocks = msg.message?.content ?? msg.content;
315ŌåÆ          if (!Array.isArray(blocks)) continue;
316ŌåÆ
317ŌåÆ          for (const block of blocks) {
318ŌåÆ            if (block.type === 'text' && block.text && chunks.length === 0) {
319ŌåÆ              print(block.text);
320ŌåÆ              chunks.push(block.text);
321ŌåÆ              print('\n');
322ŌåÆ              chunks.push('\n');
323ŌåÆ            }
324ŌåÆ          }
325ŌåÆ          continue;
326ŌåÆ        }
327ŌåÆ
328ŌåÆ        if (msg.type === 'user') {
329ŌåÆ          const blocks = msg.message?.content ?? msg.content;
330ŌåÆ          if (!Array.isArray(blocks)) continue;
331ŌåÆ
332ŌåÆ          for (const block of blocks) {
333ŌåÆ            //
334ŌåÆ            // Handling tool result
335ŌåÆ            if (block.type === 'tool_result' && block.content) {
336ŌåÆ              const rawContent =
337ŌåÆ                typeof block.content === 'string'
338ŌåÆ                  ? block.content
339ŌåÆ                  : block.content
340ŌåÆ                      .map(c => c.text ?? '')
341ŌåÆ                      .filter(Boolean)
342ŌåÆ                      .join('\n');
343ŌåÆ
344ŌåÆ              if (!rawContent) continue;
345ŌåÆ
346ŌåÆ              let trimmed = rawContent.trim().slice(0, 320);
347ŌåÆ
348ŌåÆ              const toolResult =
349ŌåÆ                trimmed && trimmed !== rawContent
350ŌåÆ                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
351ŌåÆ                  : rawContent;
352ŌåÆ
353ŌåÆ              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
354ŌåÆ              chunks.push('\n', rawContent, '\n');
355ŌåÆ            }
356ŌåÆ          }
357ŌåÆ          continue;
358ŌåÆ        }
359ŌåÆ
360ŌåÆ        if (msg.type === 'result' && msg.result) {
361ŌåÆ          if (chunks.length === 0) {
362ŌåÆ            chunks.push(msg.result);
363ŌåÆ          }
364ŌåÆ        }
365ŌåÆ      }
366ŌåÆ    }
367ŌåÆ
368ŌåÆ    if (buffer.trim()) {
369ŌåÆ      try {
370ŌåÆ        const msg: StreamMessage = JSON.parse(buffer);
371ŌåÆ        if (msg.type === 'result' && msg.result && chunks.length === 0) {
372ŌåÆ          chunks.push(msg.result);
373ŌåÆ        }
374ŌåÆ      } catch {}
375ŌåÆ    }
376ŌåÆ  } finally {
377ŌåÆ    clearTimeout(timeoutId);
378ŌåÆ    reader.releaseLock();
379ŌåÆ    currentProc = null;
380ŌåÆ    logBuffer.flush();
381ŌåÆ  }
382ŌåÆ
383ŌåÆ  const output = chunks.join('');
384ŌåÆ
385ŌåÆ  if (timedOut) {
386ŌåÆ    return {
387ŌåÆ      output,
388ŌåÆ      exitCode: 124,
389ŌåÆ      timedOut: true,
390ŌåÆ    };
391ŌåÆ  }
392ŌåÆ
393ŌåÆ  const exitCode = await proc.exited;
394ŌåÆ  println();
395ŌåÆ  return {
396ŌåÆ    output,
397ŌåÆ    exitCode,
398ŌåÆ    timedOut: false,
399ŌåÆ  };
400ŌåÆ}
