418ŌåÆasync function main(): Promise<void> {
419ŌåÆ  let cleanupCalled = false;
420ŌåÆ
421ŌåÆ  const cleanup = (signal: string) => {
422ŌåÆ    if (cleanupCalled) return;
423ŌåÆ    cleanupCalled = true;
424ŌåÆ    println();
425ŌåÆ    syslog(`Interrupted by ${signal}. Cleaning up...`);
426ŌåÆ    killCurrentProc();
427ŌåÆ    logBuffer.dispose();
428ŌåÆ    process.exit(signal === 'SIGINT' ? 130 : 143);
429ŌåÆ  };
430ŌåÆ
431ŌåÆ  process.on('SIGINT', () => cleanup('SIGINT'));
432ŌåÆ  process.on('SIGTERM', () => cleanup('SIGTERM'));
433ŌåÆ
434ŌåÆ  await checkDependencies();
435ŌåÆ
436ŌåÆ  writeFileSync(CONFIG.logFile, '');
437ŌåÆ
438ŌåÆ  printHeader();
439ŌåÆ  syslog('Starting automated task loop...');
440ŌåÆ
441ŌåÆ  let consecutiveFailures = 0;
442ŌåÆ  const MAX_CONSECUTIVE_FAILURES = 3;
443ŌåÆ
444ŌåÆ  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
445ŌåÆ    println();
446ŌåÆ    println('==========================================', 'green');
447ŌåÆ    syslog(`Iteration #${iteration} / ${CONFIG.maxIterations}`, 'green');
448ŌåÆ    println('==========================================', 'green');
449ŌåÆ    println();
450ŌåÆ
451ŌåÆ    const { output, exitCode, timedOut } = await runIteration();
452ŌåÆ
453ŌåÆ    if (exitCode === 0) {
454ŌåÆ      syslog('Claude Code completed successfully', 'green');
455ŌåÆ      consecutiveFailures = 0;
456ŌåÆ    } else {
457ŌåÆ      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
458ŌåÆ      consecutiveFailures++;
459ŌåÆ    }
460ŌåÆ
461ŌåÆ    if (consecutiveFailures >= MAX_CONSECUTIVE_FAILURES) {
462ŌåÆ      println();
463ŌåÆ      println('==========================================', 'red');
464ŌåÆ      syslog(
465ŌåÆ        `${MAX_CONSECUTIVE_FAILURES} consecutive failures ŌĆö aborting loop`,
466ŌåÆ        'red',
467ŌåÆ      );
468ŌåÆ      println('==========================================', 'red');
469ŌåÆ      logBuffer.dispose();
470ŌåÆ      process.exit(1);
471ŌåÆ    }
472ŌåÆ
473ŌåÆ    const status = parseRalphStatus(output);
474ŌåÆ
475ŌåÆ    if (status?.exit) {
476ŌåÆ      println();
477ŌåÆ      println('==========================================', 'green');
478ŌåÆ      syslog('ALL TASKS COMPLETED!', 'green');
479ŌåÆ      syslog(`Final task:      ${status.task}`, 'green');
480ŌåÆ      syslog(`Remaining:       ${status.remaining}`, 'green');
481ŌåÆ      syslog(`Total iterations: ${iteration}`, 'green');
482ŌåÆ      println('==========================================', 'green');
483ŌåÆ      logBuffer.dispose();
484ŌåÆ      process.exit(0);
485ŌåÆ    }
486ŌåÆ
487ŌåÆ    if (status) {
488ŌåÆ      syslog(
489ŌåÆ        `Task done: "${status.task}" ŌĆö ${status.remaining} remaining`,
490ŌåÆ        'blue',
491ŌåÆ      );
492ŌåÆ    } else if (!timedOut && exitCode === 0) {
493ŌåÆ      syslog(
494ŌåÆ        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
495ŌåÆ        'yellow',
496ŌåÆ      );
497ŌåÆ    }
498ŌåÆ
499ŌåÆ    if (iteration < CONFIG.maxIterations) {
500ŌåÆ      const delaySec = CONFIG.delayBetweenIterations / 1_000;
501ŌåÆ      println();
502ŌåÆ      syslog(`Waiting ${delaySec}s before next iteration...`);
503ŌåÆ      await Bun.sleep(CONFIG.delayBetweenIterations);
504ŌåÆ    }
505ŌåÆ  }
506ŌåÆ
507ŌåÆ  println();
508ŌåÆ  println('==========================================', 'red');
509ŌåÆ  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
510ŌåÆ  syslog('Loop stopped ŌĆö tasks may still be pending', 'red');
511ŌåÆ  println('==========================================', 'red');
512ŌåÆ  logBuffer.dispose();
513ŌåÆ  process.exit(1);
514ŌåÆ}
